def validate(args, output):
    nums, indexDifference, valueDifference = args
    n = len(nums)
    if not isinstance(output, list) or len(output) != 2:
        return False
    i, j = output
    if isinstance(i, bool) or isinstance(j, bool):
        return False
    if not (isinstance(i, int) and isinstance(j, int)):
        return False
    if i == -1 and j == -1:
        for a in range(n):
            for b in range(n):
                if abs(a - b) >= indexDifference and abs(nums[a] - nums[b]) >= valueDifference:
                    return False
        return True
    if not (0 <= i < n and 0 <= j < n):
        return False
    return abs(i - j) >= indexDifference and abs(nums[i] - nums[j]) >= valueDifference

