    const n = nums.length;
    if (!Array.isArray(output) || output.length !== 2) return false;
    const [i, j] = output;
    if (!Number.isInteger(i) || !Number.isInteger(j)) return false;
    if (i === -1 && j === -1) {
        for (let a = 0; a < n; a++) {
            for (let b = 0; b < n; b++) {
                if (Math.abs(a - b) >= indexDifference && Math.abs(nums[a] - nums[b]) >= valueDifference) {
                    return false;
                }
            }
        }
        return true;
    }
    if (!(i >= 0 && i < n && j >= 0 && j < n)) return false;
    return Math.abs(i - j) >= indexDifference && Math.abs(nums[i] - nums[j]) >= valueDifference;
}

